const body = $json.body ?? $json;
const traceId = body.traceId || body.jobId || `trace-${Date.now()}`;

let userText = String(body.userText || '').trim();
userText = userText.replace(/[\u2018\u2019]/g, "'").replace(/[\u201C\u201D]/g, '"');
userText = userText.replace(/[ \t\n\r]+/g, ' ').trim().slice(0, 500);

const locale = String(body.locale || body.voiceLanguage || 'en').slice(0, 16);
const systemPrompt = String(body.systemPrompt || '').trim().slice(0, 2000);
const config = (body.config && typeof body.config === 'object') ? body.config : {};
const messages = (Array.isArray(body.messages) ? body.messages : [])
  .filter(m => m && String(m.content || '').trim().length > 0)
  .slice(-10);

return [{ json: {
  traceId,
  roomId: body.roomId || null,
  jobId: body.jobId || null,
  userId: body.userId || null,
  deviceId: body.deviceId || null,
  userText,
  messages,
  locale,
  systemPrompt,
  config,
  startedAt: new Date().toISOString()
}}];

const body = $json;
const pCfg = body.config || {};

function resolveEnv(varName, def) {
  try { const v = $env[varName]; if (v != null && v !== '') return v; } catch {}
  try { const v = $vars[varName]; if (v != null && v !== '') return v; } catch {}
  return def;
}

function resolve(pv, varName, def) {
  if (pv != null && pv !== '') return pv;
  return resolveEnv(varName, def);
}

const cfg = {
  intentModel:       resolve(pCfg.intentModel,   'INTENT_MODEL',    'qwen3.5:9b'),
  intentBaseUrl:     resolve(pCfg.intentBaseUrl,  'INTENT_BASE_URL', 'https://ollama.drascom.uk').replace(/\/$/, ''),
  intentTemperature: parseFloat(resolve(pCfg.intentTemperature, 'INTENT_TEMPERATURE', 0.1)) || 0.1,
  replyModel:        resolve(pCfg.replyModel,     'REPLY_MODEL',     'qwen3.5:9b'),
  replyBaseUrl:      resolve(pCfg.replyBaseUrl,   'REPLY_BASE_URL',  'https://ollama.drascom.uk').replace(/\/$/, ''),
  replyTemperature:  parseFloat(resolve(pCfg.replyTemperature, 'REPLY_TEMPERATURE', 0.25)) || 0.25,
  replyMaxTokens:    parseInt(resolve(pCfg.replyMaxTokens, 'REPLY_MAX_TOKENS', 150)) || 150,
  apiBaseUrl:        resolve(pCfg.apiBaseUrl,     'API_BASE_URL',    'https://api.coziyoo.com').replace(/\/$/, ''),
  apiSecret:         resolveEnv('AI_SERVER_SHARED_SECRET', 'change_me_ai_server_shared_secret_min_16'),
};

return [{ json: { ...body, cfg } }];

const raw = $json?.output || '';
let parsed = {};
try {
  const cleaned = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch { parsed = {}; }

const prev = $('Resolve Config').item.json;

const VALID = new Set(['greeting','farewell','menu_browse','product_search','price_check','add_to_cart','view_cart','checkout','order_status','help','fallback']);
const intent = VALID.has(parsed.intent) ? parsed.intent : 'fallback';
const confidence = typeof parsed.confidence === 'number' ? Math.min(1, Math.max(0, parsed.confidence)) : 0.7;
const slots = { productName: parsed.slots?.productName || null, quantity: parsed.slots?.quantity || null };
const ask = String(parsed.ask || '');

return [{ json: { ...prev, intent, confidence, slots, ask, intentRaw: raw } }];

const llmText = String($json?.output || '').trim();
const ctx = $('Parse Intent').item.json;
return [{ json: { replyText: llmText || 'Here are the available options.', actions: [], meta: { intent: ctx.intent, traceId: ctx.traceId, locale: ctx.locale } } }];

const llmText = String($json?.output || '').trim();
const ctx = $('Parse Intent').item.json;
return [{ json: { replyText: llmText || 'Added to your cart.', actions: [], meta: { intent: ctx.intent, traceId: ctx.traceId } } }];

const llmText = String($json?.output || '').trim();
const ctx = $('Parse Intent').item.json;
const orderId = $('Create Order').item?.json?.data?.orderId || null;
return [{ json: { replyText: llmText || (orderId ? 'Your order has been placed.' : 'I could not place the order, please try again.'), actions: orderId ? [{ name: 'navigate', params: { screen: 'OrderDetail', orderId } }] : [], meta: { intent: 'checkout', traceId: ctx.traceId, orderId } } }];

const llmText = String($json?.output || '').trim();
const ctx = $('Parse Intent').item.json;
return [{ json: { replyText: llmText || 'Your cart is empty. Please add some items first.', actions: [], meta: { intent: ctx.intent, traceId: ctx.traceId } } }];

const llmText = String($json?.output || '').trim();
const ctx = $('Parse Intent').item.json;

const fallback = ctx.ask || (ctx.intent === 'fallback' ? "I'm not sure I understood. Could you rephrase?" : 'How can I help you with your order?');

return [{ json: {
  replyText: llmText || fallback,
  actions: [],
  meta: {
    intent: ctx.intent,
    confidence: ctx.confidence,
    slots: ctx.slots,
    traceId: ctx.traceId,
    locale: ctx.locale,
    model: ctx.cfg?.replyModel
  }
}}];
